CREATE DATABASE IF NOT EXISTS demo;
       
CREATE TABLE demo.series_forecast
(
    series_id UInt32,
    recorded_at DateTime('UTC'),
    event_time DateTime('UTC'),
    forecast_at DateTime('UTC'),
    ingested_at DateTime64(9, 'UTC'),
    "value" Nullable(Decimal(38, 10)),
    quality UInt8 DEFAULT 0
)
ENGINE = MergeTree()
PRIMARY KEY (series_id, event_time, forecast_at)
ORDER BY (series_id, event_time, forecast_at, recorded_at)
SETTINGS index_granularity = 8192;


CREATE TABLE demo.series_actual
(
    series_id UInt32,
    recorded_at DateTime('UTC'),
    event_time DateTime('UTC'),
    ingested_at DateTime64(9, 'UTC'),
    "value" Nullable(Decimal(38, 10)),
    quality UInt8 DEFAULT 0
)
ENGINE = MergeTree()
PRIMARY KEY (series_id, event_time)
ORDER BY (series_id, event_time, recorded_at)
SETTINGS index_granularity = 8192;


